using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(entity =>
        {
            // Breaking change 1: EF 9 renamed "Discriminator" to "$type".
            // Existing documents use "Discriminator", so we must preserve it.
            entity.HasDiscriminator().HasValue("Blog");
            entity.Property<string>("$type").ToJsonProperty("Discriminator");

            // Breaking change 2: EF 9 changed id format from "EntityType|Key" to just "Key".
            // Existing documents use "Blog|1" format, so we must opt back in.
            entity.HasPartitionKey(b => b.Id);
            entity.Property(b => b.Id)
                  .ToJsonProperty("id")
                  .HasValueGenerator<LegacyIdValueGenerator>();

            // Breaking change 3: EF 9 removed support for HasIndex on Cosmos.
            // Cosmos DB does not support secondary indexes via EF; remove HasIndex call.
            // (HasIndex removed — was a no-op previously, now throws)
        });
    }

    protected override void OnConfiguring(DbContextOptionsBuilder options)
    {
        // Breaking change 4: Sync I/O now throws by default in EF 9 Cosmos provider.
        // Existing code uses .ToList() and .SaveChanges() (sync).
        // Either migrate to async or opt back in:
        options.UseCosmos("AccountEndpoint=...;AccountKey=...", "BlogDb",
            cosmosOptions => { });

        // Opt back into sync I/O (required until code is migrated to async)
        AppContext.SetSwitch("Microsoft.EntityFrameworkCore.Cosmos.AllowSyncIO", true);
    }
}

